import { useState } from "react";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Label } from "../components/ui/label";
import { Textarea } from "../components/ui/textarea";
import { Switch } from "../components/ui/switch";
import { Bot, Plus, Trash2, Save } from "lucide-react";
import { toast } from "sonner";

export default function Chatbot() {
  const { chatbot, setChatbot } = useData();
  const [form, setForm] = useState(chatbot);

  const set = (k, v) => setForm({ ...form, [k]: v });
  const updateFaq = (id, k, v) =>
    setForm({ ...form, faqs: form.faqs.map((f) => (f.id === id ? { ...f, [k]: v } : f)) });
  const addFaq = () =>
    setForm({ ...form, faqs: [...form.faqs, { id: Date.now(), question: "", answer: "" }] });
  const removeFaq = (id) => setForm({ ...form, faqs: form.faqs.filter((f) => f.id !== id) });

  const handleSave = () => {
    setChatbot(form);
    toast.success("Pengaturan chatbot disimpan");
  };

  return (
    <div className="max-w-[1100px]" data-testid="chatbot-page">
      <h1 className="text-3xl font-extrabold text-gray-900">Pengaturan Chatbot</h1>
      <p className="text-sm text-gray-500 mt-1 mb-8">Konfigurasi balasan otomatis untuk pelanggan</p>

      {/* Status card */}
      <div className="mpl-card p-7 mb-6 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-xl bg-[#FEF3C7] flex items-center justify-center">
            <Bot className="w-6 h-6 text-[#F59E0B]" />
          </div>
          <div>
            <div className="font-bold text-gray-900">Status Chatbot</div>
            <div className="text-xs text-gray-500 mt-0.5">Aktifkan untuk membalas pesan customer otomatis</div>
          </div>
        </div>
        <Switch
          checked={form.enabled}
          onCheckedChange={(v) => set("enabled", v)}
          data-testid="chatbot-toggle"
        />
      </div>

      <div className="mpl-card p-7 mb-6">
        <h3 className="font-bold text-gray-900 mb-5">Pesan Otomatis</h3>
        <div className="space-y-5">
          <div>
            <Label className="text-[10px] tracking-wider uppercase text-gray-500 font-semibold">Pesan Sambutan</Label>
            <Textarea
              data-testid="greeting-input"
              rows={2}
              className="mt-1.5"
              value={form.greeting}
              onChange={(e) => set("greeting", e.target.value)}
            />
          </div>
          <div>
            <Label className="text-[10px] tracking-wider uppercase text-gray-500 font-semibold">Pesan Tidak Dimengerti (Fallback)</Label>
            <Textarea
              data-testid="fallback-input"
              rows={2}
              className="mt-1.5"
              value={form.fallback}
              onChange={(e) => set("fallback", e.target.value)}
            />
          </div>
        </div>
      </div>

      <div className="mpl-card p-7 mb-6">
        <div className="flex items-center justify-between mb-5">
          <h3 className="font-bold text-gray-900">FAQ Otomatis</h3>
          <Button onClick={addFaq} data-testid="add-faq-btn" variant="outline" className="h-9 px-4 text-sm">
            <Plus className="w-4 h-4 mr-1.5" /> Tambah FAQ
          </Button>
        </div>
        <div className="space-y-4">
          {form.faqs.map((faq) => (
            <div key={faq.id} className="border border-gray-200 rounded-xl p-4" data-testid={`faq-row-${faq.id}`}>
              <div className="flex items-start gap-3">
                <div className="flex-1 space-y-3">
                  <Input
                    placeholder="Pertanyaan..."
                    value={faq.question}
                    onChange={(e) => updateFaq(faq.id, "question", e.target.value)}
                    data-testid={`faq-q-${faq.id}`}
                  />
                  <Textarea
                    placeholder="Jawaban..."
                    rows={2}
                    value={faq.answer}
                    onChange={(e) => updateFaq(faq.id, "answer", e.target.value)}
                    data-testid={`faq-a-${faq.id}`}
                  />
                </div>
                <button
                  onClick={() => removeFaq(faq.id)}
                  data-testid={`faq-remove-${faq.id}`}
                  className="p-2 text-gray-400 hover:text-red-500"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-end">
        <Button onClick={handleSave} data-testid="save-chatbot-btn" className="mpl-btn-primary h-11 px-6">
          <Save className="w-4 h-4 mr-2" /> Simpan Pengaturan
        </Button>
      </div>
    </div>
  );
}
